example.code:
import { createContext, useContext, type ReactNode } from 'react';
import { cn } from '@/lib/utils';

interface CardContextValue { variant: 'default' | 'outlined' }
const CardContext = createContext<CardContextValue | null>(null);

function useCardContext() {
  const ctx = useContext(CardContext);
  if (!ctx) throw new Error('Card components must be used within Card');
  return ctx;
}

export function Card({ variant = 'default', className, children }: {
  variant?: 'default' | 'outlined'; className?: string; children: ReactNode;
}) {
  return (
    <CardContext.Provider value={{ variant }}>
      <div className={cn('rounded-lg bg-card', variant === 'outlined' && 'border', className)}>
        {children}
      </div>
    </CardContext.Provider>
  );
}

export function CardHeader({ className, children }: { className?: string; children: ReactNode }) {
  return <div className={cn('flex flex-col space-y-1.5 p-6', className)}>{children}</div>;
}

export function CardContent({ className, children }: { className?: string; children: ReactNode }) {
  return <div className={cn('p-6 pt-0', className)}>{children}</div>;
}

// Ergonomic namespace alias (tree-shaking still works via named exports above)
Card.Header = CardHeader;
Card.Content = CardContent;
